<?php
namespace Database\Seeders;use Illuminate\Database\Seeder;use Spatie\Permission\Models\{Role,Permission};use App\Models\User;
class RolePermissionSeeder extends Seeder{public function run():void{$permissions=['verify usaha','verify halal','manage user','manage category','manage review report','manage reservation','view dashboard','manage culinary','manage gallery','manage menu','reply review','search culinary','manage favorite','write review','create reservation','navigate maps'];foreach($permissions as $p)Permission::firstOrCreate(['name'=>$p]);$admin=Role::firstOrCreate(['name'=>'admin_dinas']);$owner=Role::firstOrCreate(['name'=>'pemilik_usaha']);$tourist=Role::firstOrCreate(['name'=>'wisatawan']);$admin->syncPermissions($permissions);$owner->syncPermissions(['manage culinary','manage gallery','manage menu','manage reservation','reply review']);$tourist->syncPermissions(['search culinary','manage favorite','write review','create reservation','navigate maps']);User::firstOrCreate(['email'=>'admin@palembang.go.id'],['name'=>'Admin Dinas Pariwisata','password'=>bcrypt('password'),'status'=>'active'])->assignRole($admin);}}
